// Loading Component
export const Loading = ({ text = "Đang tải...", layout = "inline", type = "spinner", size = "md" }) => (
  <div className={`loading ${layout} ${type} ${size}`} style={{
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    padding: layout === 'fullscreen' ? '40px' : '20px',
    ...(layout === 'fullscreen' && {
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: '#f8f9fa',
      zIndex: 9999
    })
  }}>
    <div style={{
      width: size === 'lg' ? '48px' : size === 'sm' ? '24px' : '32px',
      height: size === 'lg' ? '48px' : size === 'sm' ? '24px' : '32px',
      border: `${size === 'lg' ? '4px' : '3px'} solid #f3f3f3`,
      borderTop: `${size === 'lg' ? '4px' : '3px'} solid #3498db`,
      borderRadius: '50%',
      animation: 'spin 1s linear infinite',
      marginBottom: '12px'
    }}></div>
    <p style={{ 
      color: '#666', 
      margin: 0, 
      fontSize: size === 'lg' ? '16px' : size === 'sm' ? '12px' : '14px' 
    }}>
      {text}
    </p>
    <style jsx>{`
      @keyframes spin {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(360deg); }
      }
    `}</style>
  </div>
);

// FullscreenLoading Component
export const FullscreenLoading = ({ show = false, text = "Đang tải...", subtitle = "", logo = null, type = "gradient" }) => {
  if (!show) return null;

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: type === 'gradient' 
        ? 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' 
        : '#f8f9fa',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 9999,
      color: type === 'gradient' ? 'white' : '#333'
    }}>
      <div style={{ textAlign: 'center', maxWidth: '400px', padding: '40px' }}>
        {logo}
        <Loading text={text} size="lg" />
        {subtitle && (
          <p style={{ 
            color: type === 'gradient' ? 'rgba(255,255,255,0.8)' : '#666', 
            marginTop: '16px',
            fontSize: '14px'
          }}>
            {subtitle}
          </p>
        )}
      </div>
    </div>
  );
};

